import { useCallback, useEffect, useState } from 'react';
import { catalogUiSchemaService } from '../../services/catalogUiSchemaService';
import type { CatalogUiSchema } from '../../types/catalogUiSchema';
import { resolveListDisplaySchema } from './listUiSchemaBootstrap';

export type UseCatalogUiSchemaOptions = {
  /** Một dòng list (vd. `items[0]`) — seed field khi chưa có record / GET lỗi. */
  sampleRow?: Record<string, unknown> | null;
};

export function useCatalogUiSchema(
  catalogKind: string,
  options?: UseCatalogUiSchemaOptions,
): {
  schema: CatalogUiSchema | null;
  loading: boolean;
  error: string | null;
  isBootstrap: boolean;
  reload: () => void;
} {
  const [schema, setSchema] = useState<CatalogUiSchema | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isBootstrap, setIsBootstrap] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const sampleRow = options?.sampleRow ?? null;

  const reload = useCallback(() => setReloadKey(k => k + 1), []);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setError(null);
    const t = setTimeout(() => {
      catalogUiSchemaService
        .get(catalogKind, false)
        .then(data => {
          if (cancelled) return;
          const resolved = resolveListDisplaySchema(catalogKind, data, sampleRow, false);
          setSchema(resolved.schema);
          setIsBootstrap(resolved.isBootstrap);
        })
        .catch(err => {
          if (cancelled) return;
          const msg = err instanceof Error ? err.message : 'Lỗi tải cấu hình hiển thị';
          setError(msg);
          const resolved = resolveListDisplaySchema(catalogKind, null, sampleRow, true);
          setSchema(resolved.schema);
          setIsBootstrap(true);
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [catalogKind, reloadKey, sampleRow]);

  return { schema, loading, error, isBootstrap, reload };
}
